const d = $input.first().json;

function normalizarTel(tel) {
  if (!tel) return null;
  const digits = String(tel).replace(/\D/g, '');
  return digits.startsWith('55') ? digits : '55' + digits;
}

const horario = new Date(d.timestamp).toLocaleString('pt-BR', {
  timeZone: 'America/Recife',
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

const emoji = d.tipo === 'temp_acima' ? '🔴'
  : d.tipo === 'temp_abaixo' ? '🔵'
  : d.tipo === 'teste_configuracao' ? '✅'
  : '⚠️';

const locStr = d.localizacao ? ` (${d.localizacao})` : '';

const linhasWA = [
  `${emoji} *ALERTA — Rizom Temp*`,
  '',
  `📍 *Equipamento:* ${d.equipamento}${locStr}`,
  d.temperatura != null ? `🌡️ *Temperatura:* ${d.temperatura}°C` : null,
  `📝 ${d.mensagem}`,
  `🕐 *Horário:* ${horario}`,
  '',
  'Acesse o painel para verificar e reconhecer o alerta.',
].filter(l => l !== null);

const tempRow = d.temperatura != null
  ? `<tr><td style="padding:8px;border:1px solid #eee"><b>Temperatura</b></td><td style="padding:8px;border:1px solid #eee">${d.temperatura}°C</td></tr>`
  : '';

const emailHtml = `<!DOCTYPE html><html><body style="font-family:sans-serif;color:#333">
<div style="max-width:600px;margin:0 auto">
  <h2 style="color:#d32f2f">${emoji} Alerta de Temperatura — Rizom Temp</h2>
  <table style="width:100%;border-collapse:collapse;margin-bottom:24px">
    <tr><td style="padding:8px;border:1px solid #eee"><b>Empresa</b></td><td style="padding:8px;border:1px solid #eee">${d.cliente_nome}</td></tr>
    <tr><td style="padding:8px;border:1px solid #eee"><b>Equipamento</b></td><td style="padding:8px;border:1px solid #eee">${d.equipamento}${locStr}</td></tr>
    ${tempRow}
    <tr><td style="padding:8px;border:1px solid #eee"><b>Ocorrência</b></td><td style="padding:8px;border:1px solid #eee">${d.mensagem}</td></tr>
    <tr><td style="padding:8px;border:1px solid #eee"><b>Horário</b></td><td style="padding:8px;border:1px solid #eee">${horario}</td></tr>
  </table>
  <p style="color:#666">Acesse o painel do Rizom Temp para verificar e reconhecer o alerta.</p>
</div></body></html>`;

return [{ json: {
  ...d,
  telefone_normalizado: normalizarTel(d.cliente_telefone),
  tem_telefone: Boolean(normalizarTel(d.cliente_telefone)),
  tem_email: Boolean(d.cliente_email),
  whatsapp_texto: linhasWA.join('\n'),
  email_html: emailHtml,
  email_assunto: `[${emoji.replace(/\s/g,'')}] ${d.equipamento} — ${d.mensagem.slice(0,60)}`,
}}];
